 27→export const createSandbox = orgAction(
 28→  z.object({
 29→    name: z.string().min(1, "Name is required").max(50, "Name is too long"),
 30→    telegramBotToken: z
 31→      .string()
 32→      .regex(/^\d+:[A-Za-z0-9_-]+$/, "Invalid bot token format"),
 33→  }),
 34→  async ({ user, organizationId }, input) => {
 35→    // Role gate
 36→    await requireAdminOrOwner(user.id, organizationId);
 37→
 38→    // One-sandbox-per-org (server-side only, no DB constraint)
 39→    const existing = await sandboxRepo.findByOrg(organizationId);
 40→    if (existing.length > 0)
 41→      throw new Error(
 42→        "Your organization already has a sandbox. Delete it before deploying a new one.",
 43→      );
 44→
 45→    const openrouterApiKey = env.OPENROUTER_API_KEY;
 46→    if (!openrouterApiKey)
 47→      throw new Error("OPENROUTER_API_KEY is not configured");
 48→
 49→    const sandboxId = crypto.randomUUID();
 50→    const webhookSecret = crypto.randomUUID();
 51→    const baseUrl = env.WEBHOOK_BASE_URL ?? clientEnv.NEXT_PUBLIC_SERVER_URL;
 52→    const webhookUrl = `${baseUrl}/api/telegram/${sandboxId}`;
 53→
 54→    const runtime = await Sandbox.betaCreate(E2B_TEMPLATE_NAME, {
 55→      apiKey: getE2BApiKey(),
 56→      autoPause: true,
 57→      timeoutMs: E2B_TIMEOUT_MS,
 58→      metadata: { organizationId, name: input.name },
 59→    });
 60→
 61→    try {
 62→      await runOrThrow(
 63→        runtime,
 64→        `openclaw onboard \
 65→        --non-interactive --accept-risk \
 66→        --flow quickstart \
 67→        --gateway-bind loopback --gateway-auth token \
 68→        --skip-health \
 69→        --auth-choice openrouter-api-key \
 70→        --openrouter-api-key "${openrouterApiKey}"`,
 71→        "Credential injection",
 72→      );
 73→
 74→      await runOrThrow(
 75→        runtime,
 76→        `jq \
 77→          --arg botToken "${input.telegramBotToken}" \
 78→          --arg webhookUrl "${webhookUrl}" \
 79→          --arg webhookSecret "${webhookSecret}" \
 80→          '
 81→            .plugins.entries.telegram.enabled = true |
 82→            .channels.telegram.enabled = true |
 83→            .channels.telegram.botToken = $botToken |
 84→            .channels.telegram.webhookUrl = $webhookUrl |
 85→            .channels.telegram.webhookSecret = $webhookSecret
 86→          ' ~/.openclaw/openclaw.json > /tmp/openclaw.json && mv /tmp/openclaw.json ~/.openclaw/openclaw.json`,
 87→        "Config patch",
 88→      );
 89→
 90→      await runOrThrow(runtime, "openclaw gateway start", "Gateway start");
 91→
 92→      const info = await runtime.getInfo({ requestTimeoutMs: 15_000 });
 93→
 94→      const [telegramBotTokenEnc, webhookSecretEnc] = await Promise.all([
 95→        encrypt(input.telegramBotToken),
 96→        encrypt(webhookSecret),
 97→      ]);
 98→
 99→      return await sandboxRepo.create({
100→        organizationId,
101→        id: sandboxId,
102→        name: input.name,
103→        e2bSandboxId: runtime.sandboxId,
104→        e2bTemplateId: info.templateId,
105→        telegramBotTokenEnc,
106→        webhookSecretEnc,
107→        deploymentStatus: "running",
108→      });
109→    } catch (error) {
110→      await runtime.kill().catch(() => undefined);
111→      throw error;
112→    }
113→  },
114→);
