116→export const deleteSandbox = orgAction(
117→  z.object({ sandboxId: z.string().min(1) }),
118→  async ({ user, organizationId }, input) => {
119→    // Role gate
120→    await requireAdminOrOwner(user.id, organizationId);
121→
122→    const sandbox = await sandboxRepo.findById(input.sandboxId, organizationId);
123→    if (!sandbox) throw new Error("Sandbox not found");
124→
125→    if (sandbox.e2bSandboxId) {
126→      const runtime = await connectSandbox(sandbox.e2bSandboxId).catch(
127→        () => null,
128→      );
129→      await runtime?.kill().catch(() => undefined);
130→    }
131→
132→    await sandboxRepo.deleteById(input.sandboxId, organizationId);
133→  },
134→);
