  1→"use client";
  2→
  3→import { Bot, Loader2 } from "lucide-react";
  4→import { useState } from "react";
  5→import { Button } from "@/components/ui/button";
  6→import {
  7→  Dialog,
  8→  DialogContent,
  9→  DialogDescription,
 10→  DialogFooter,
 11→  DialogHeader,
 12→  DialogTitle,
 13→} from "@/components/ui/dialog";
 14→import { Input } from "@/components/ui/input";
 15→import { Label } from "@/components/ui/label";
 16→import { useCreateSandbox } from "../_hooks/use-sandboxes";
 17→
 18→interface CreateSandboxDialogProps {
 19→  open: boolean;
 20→  onOpenChange: (open: boolean) => void;
 21→  onSubscriptionRequired?: () => void;
 22→}
 23→
 24→export function CreateSandboxDialog({
 25→  open,
 26→  onOpenChange,
 27→  onSubscriptionRequired,
 28→}: CreateSandboxDialogProps) {
 29→  const [name, setName] = useState("");
 30→  const [telegramBotToken, setTelegramBotToken] = useState("");
 31→  const [error, setError] = useState<string | null>(null);
 32→  const { mutate: createSandbox, isPending } = useCreateSandbox();
 33→
 34→  function handleOpenChange(next: boolean) {
 35→    if (isPending) return;
 36→    if (!next) {
 37→      setName("");
 38→      setTelegramBotToken("");
 39→      setError(null);
 40→    }
 41→    onOpenChange(next);
 42→  }
 43→
 44→  function handleSubmit(e: React.FormEvent) {
 45→    e.preventDefault();
 46→
 47→    if (!(name.trim() && telegramBotToken.trim())) return;
 48→
 49→    setError(null);
 50→    createSandbox(
 51→      { name: name.trim(), telegramBotToken: telegramBotToken.trim() },
 52→      {
 53→        onSuccess: () => handleOpenChange(false),
 54→        onError: (err) => {
 55→          if ((err as { code?: string }).code === "SUBSCRIPTION_REQUIRED") {
 56→            handleOpenChange(false);
 57→            onSubscriptionRequired?.();
 58→            return;
 59→          }
 60→          setError(err.message ?? "Failed to create sandbox");
 61→        },
 62→      },
 63→    );
 64→  }
 65→
 66→  const canSubmit = !!name.trim() && !!telegramBotToken.trim() && !isPending;
 67→
 68→  return (
 69→    <Dialog open={open} onOpenChange={handleOpenChange}>
 70→      <DialogContent className="sm:max-w-md" preventClose={isPending}>
 71→        <DialogHeader>
 72→          <div className="flex items-center gap-2">
 73→            <div className="flex size-8 items-center justify-center rounded-md bg-primary/10 text-primary">
 74→              <Bot className="size-4" />
 75→            </div>
 76→            <DialogTitle>Deploy Bot</DialogTitle>
 77→          </div>
 78→          <DialogDescription>
 79→            Deploy a hosted OpenClaw Telegram bot.
 80→          </DialogDescription>
 81→        </DialogHeader>
 82→
 83→        <form onSubmit={handleSubmit} className="space-y-4">
 84→          <div className="space-y-2">
 85→            <Label htmlFor="sandbox-name">Name</Label>
 86→            <Input
 87→              id="sandbox-name"
 88→              placeholder="my-trading-bot"
 89→              value={name}
 90→              onChange={(e) => setName(e.target.value)}
 91→              disabled={isPending}
 92→              autoComplete="off"
 93→            />
 94→          </div>
 95→          <div className="space-y-2">
 96→            <Label htmlFor="telegram-bot-token">Telegram Bot Token</Label>
 97→            <Input
 98→              id="telegram-bot-token"
 99→              placeholder="123456:ABC-DEF..."
100→              value={telegramBotToken}
101→              onChange={(e) => setTelegramBotToken(e.target.value)}
102→              disabled={isPending}
103→              autoComplete="off"
104→            />
105→            <p className="text-xs text-muted-foreground">
106→              From{" "}
107→              <a
108→                href="https://t.me/BotFather"
109→                target="_blank"
110→                rel="noopener noreferrer"
111→                className="underline underline-offset-2"
112→              >
113→                @BotFather
114→              </a>{" "}
115→              — create a bot and paste the token here.
116→            </p>
117→          </div>
118→
119→          {error && (
120→            <p className="text-sm text-destructive">{error}</p>
121→          )}
122→
123→          <DialogFooter>
124→            <Button
125→              type="button"
126→              variant="outline"
127→              onClick={() => handleOpenChange(false)}
128→              disabled={isPending}
129→            >
130→              Cancel
131→            </Button>
132→            <Button type="submit" disabled={!canSubmit}>
133→              {isPending ? (
134→                <>
135→                  <Loader2 className="mr-2 size-4 animate-spin" />
136→                  Deploying…
137→                </>
138→              ) : (
139→                "Deploy"
140→              )}
141→            </Button>
142→          </DialogFooter>
143→        </form>
144→      </DialogContent>
145→    </Dialog>
146→  );
147→}
