 1→"use client";
 2→
 3→import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
 4→import { useRouter } from "next/navigation";
 5→import { authClient } from "@/lib/auth-client";
 6→import { sandboxKeys } from "@/lib/sandbox";
 7→import { createSandbox, getSandboxes } from "@/server/actions/sandbox.actions";
 8→
 9→export function useSandboxes() {
10→  const { data: activeOrg } = authClient.useActiveOrganization();
11→  const orgId = activeOrg?.id;
12→
13→  return useQuery({
14→    queryKey: orgId ? sandboxKeys.all(orgId) : ["sandboxes", null],
15→    queryFn: async () => {
16→      const result = await getSandboxes();
17→      if (result && typeof result === "object" && "error" in result) {
18→        throw Object.assign(new Error(String(result.error)), { code: result.error });
19→      }
20→      return result;
21→    },
22→    enabled: !!orgId,
23→  });
24→}
25→
26→export function useCreateSandbox() {
27→  const queryClient = useQueryClient();
28→  const router = useRouter();
29→  const { data: activeOrg } = authClient.useActiveOrganization();
30→  const orgId = activeOrg?.id;
31→
32→  return useMutation({
33→    mutationFn: async (input: { name: string; telegramBotToken: string }) => {
34→      const result = await createSandbox(input);
35→      if (result && typeof result === "object" && "error" in result) {
36→        // Re-throw as a client-side error so TanStack Query routes it to onError.
37→        // Attaching a `code` property avoids relying on err.message, which Next.js
38→        // redacts for server action errors in production.
39→        throw Object.assign(new Error(String(result.error)), { code: result.error });
40→      }
41→      return result;
42→    },
43→    onSuccess: (sandbox) => {
44→      if (orgId) {
45→        queryClient.invalidateQueries({ queryKey: sandboxKeys.all(orgId) });
46→      }
47→      if (sandbox) router.push(`/sandboxes/${sandbox.id}`);
48→    },
49→  });
50→}
