 1→import { type NextRequest, NextResponse } from "next/server";
 2→import { connectSandbox } from "@/lib/e2b";
 3→import { sandboxRepo } from "@/server/db/repos/sandbox.repo";
 4→
 5→export const maxDuration = 60;
 6→
 7→export async function POST(
 8→  req: NextRequest,
 9→  { params }: { params: Promise<{ sandboxId: string }> },
10→) {
11→  const { sandboxId } = await params;
12→
13→  const row = await sandboxRepo.findByIdPublic(sandboxId);
14→  const webhookSecret = row?.webhookSecret;
15→  const e2bSandboxId = row?.e2bSandboxId;
16→  const telegramBotToken = row?.telegramBotToken;
17→
18→  if (!(webhookSecret && e2bSandboxId && telegramBotToken)) {
19→    return new NextResponse(null, { status: 404 });
20→  }
21→
22→  const incomingSecret = req.headers.get("x-telegram-bot-api-secret-token");
23→  if (incomingSecret !== webhookSecret) {
24→    return new NextResponse(null, { status: 401 });
25→  }
26→
27→  const body = await req.text();
28→
29→  const tag = `[telegram-relay] sandbox=${e2bSandboxId}`;
30→  const t0 = Date.now();
31→  try {
32→    await connectSandbox(e2bSandboxId);
33→    console.warn(`${tag} connect=${Date.now() - t0}ms`);
34→
35→    // Await delivery to the openclaw gateway — the gateway responds immediately
36→    // (200) and processes the AI turn asynchronously, so this doesn't block
37→    // for the full AI response time. Awaiting ensures the message is delivered
38→    // before we return 200 to Telegram, and lets fetch errors fall into the
39→    // catch block below so the user gets an error notification.
40→    const t1 = Date.now();
41→    await fetch(`https://8787-${e2bSandboxId}.e2b.app/telegram-webhook`, {
42→      method: "POST",
43→      headers: {
44→        "Content-Type": "application/json",
45→        "X-Telegram-Bot-Api-Secret-Token": webhookSecret,
46→      },
47→      body,
48→    });
49→    console.warn(`${tag} fetch=${Date.now() - t1}ms total=${Date.now() - t0}ms`);
50→
51→  } catch (err) {
52→    console.error(`${tag} failed after ${Date.now() - t0}ms`, err);
53→
54→    // Best-effort: notify the user in Telegram that the agent is unavailable.
55→    // Parse the chat_id from the incoming update so we know where to reply.
56→    try {
57→      const update = JSON.parse(body) as {
58→        message?: { chat?: { id?: number } };
59→        callback_query?: { message?: { chat?: { id?: number } } };
60→      };
61→      const chatId =
62→        update.message?.chat?.id ??
63→        update.callback_query?.message?.chat?.id;
64→
65→      if (chatId) {
66→        await fetch(
67→          `https://api.telegram.org/bot${telegramBotToken}/sendMessage`,
68→          {
69→            method: "POST",
70→            headers: { "Content-Type": "application/json" },
71→            body: JSON.stringify({
72→              chat_id: chatId,
73→              text: "⚠️ The agent is currently unavailable. Please try again in a moment.",
74→            }),
75→          },
76→        );
77→      }
78→    } catch (notifyErr) {
79→      console.error(`${tag} failed to send error notification`, notifyErr);
80→    }
81→
82→    // Return 200 anyway — Telegram retries on non-200 and would cause duplicate messages
83→  }
84→
85→  return new NextResponse(null, { status: 200 });
86→}
