 11→    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
 12→    const result = await runOrThrow(
 13→      runtime,
 14→      `openclaw models status --json`,
 15→      "getModelsStatus",
 16→    );
 17→    try {
 18→      return JSON.parse(result.stdout.trim() || "{}") as Record<
 19→        string,
