  3→import { eq } from "drizzle-orm";
  4→import { z } from "zod";
  5→import { PlatformInvitationEmail } from "@/emails/platform-invitation-email";
  6→import { env as clientEnv } from "@/env/client";
  7→import { auth } from "@/lib/auth";
  8→import { connectSandbox } from "@/lib/e2b";
  9→import { sendEmail } from "@/lib/email/send";
 10→import { db } from "@/server/db";
 11→import { user } from "@/server/db/models/auth.model";
