 17→// ── Types ─────────────────────────────────────────────────────────────────────
 18→
 19→type AdminUser = {
 20→  id: string;
 21→  name: string;
 22→  email: string;
 23→  emailVerified: boolean;
 24→  image: string | null | undefined;
 25→  createdAt: Date;
 26→  role: string | null | undefined;
 27→  banned: boolean | null | undefined;
 28→};
 29→
 30→type ListUsersResult = {
 31→  users: AdminUser[];
 32→  total: number;
 33→  limit: number | undefined;
 34→  offset: number | undefined;
 35→};
 36→
 37→export type AdminSandbox = {
 38→  id: string;
 39→  name: string;
 40→  organizationId: string;
 41→  orgName: string | null;
 42→  orgSlug: string | null;
 43→  e2bSandboxId: string | null;
 44→  deploymentStatus: string;
