 49→// ── Overview actions ───────────────────────────────────────────────────────────
 50→
 51→export const getOverviewStatsAction = adminAction(async () =>
 52→  adminRepo.getOverviewStats(),
 53→);
 54→
 55→export const getOverviewSeriesAction = adminAction(
 56→  z.object({
 57→    start: z.coerce.date(),
 58→    end: z.coerce.date(),
 59→    interval: z.enum(["day", "week", "month"]).optional(),
 60→  }),
 61→  async (_ctx, { start, end, interval }) =>
 62→    adminRepo.getOverviewSeries(start, end, interval ?? "month"),
 63→);
 64→
 65→// ── User actions ──────────────────────────────────────────────────────────────
 66→
 67→export const listUsersAction = adminAction(
 68→  z
 69→    .object({
 70→      searchValue: z.string().optional(),
 71→      searchField: z.enum(["email", "name"]).optional(),
 72→      sortBy: z.string().optional(),
 73→      sortDirection: z.enum(["asc", "desc"]).optional(),
 74→      limit: z.number().int().positive().max(100).optional(),
 75→      offset: z.number().int().min(0).optional(),
 76→    })
 77→    .optional(),
 78→  async (ctx, params) => {
 79→    const result = await auth.api.listUsers({
 80→      query: {
 81→        searchValue: params?.searchValue,
 82→        searchField: params?.searchField,
 83→        sortBy: params?.sortBy ?? "createdAt",
 84→        sortDirection: params?.sortDirection ?? "desc",
 85→        limit: params?.limit ?? 50,
 86→        offset: params?.offset ?? 0,
 87→      },
 88→      headers: ctx.headers,
 89→    });
 90→    return result as unknown as ListUsersResult;
 91→  },
 92→);
 93→
 94→export const setUserRoleAction = adminAction(
 95→  z.object({
 96→    userId: z.string().min(1),
 97→    role: z.enum(["user", "admin"]),
 98→  }),
 99→  async (ctx, { userId, role }) => {
100→    await auth.api.setRole({
101→      body: { userId, role },
102→      headers: ctx.headers,
103→    });
104→  },
105→);
106→
107→export const banUserAction = adminAction(
108→  z.object({
109→    userId: z.string().min(1),
110→    banReason: z.string().max(500).optional(),
111→  }),
112→  async (ctx, { userId, banReason }) => {
113→    await auth.api.banUser({
114→      body: { userId, banReason: banReason ?? "Banned by admin" },
115→      headers: ctx.headers,
116→    });
117→  },
118→);
119→
120→export const unbanUserAction = adminAction(
121→  z.object({ userId: z.string().min(1) }),
122→  async (ctx, { userId }) => {
123→    await auth.api.unbanUser({
124→      body: { userId },
125→      headers: ctx.headers,
126→    });
127→  },
128→);
129→
130→// ── Sandbox actions ───────────────────────────────────────────────────────────
131→
132→export const listAllSandboxesAction = adminAction(
133→  async (): Promise<AdminSandbox[]> => {
134→    const rows = await sandboxRepo.findAll();
135→    return rows as AdminSandbox[];
136→  },
137→);
138→
139→export const deleteSandboxAdminAction = adminAction(
140→  z.object({ sandboxId: z.string().min(1) }),
141→  async (_ctx, { sandboxId }) => {
142→    const sandbox = await sandboxRepo.findByIdAdmin(sandboxId);
143→    if (!sandbox) throw new Error("Sandbox not found");
144→
145→    if (sandbox.e2bSandboxId) {
146→      const runtime = await connectSandbox(sandbox.e2bSandboxId).catch(
147→        () => null,
148→      );
149→      await runtime?.kill().catch(() => undefined);
150→    }
151→
152→    await sandboxRepo.deleteByIdAdmin(sandboxId);
153→  },
154→);
155→
156→// ── Invite actions ────────────────────────────────────────────────────────────
157→
158→const INVITE_EXPIRATION_MS = 7 * 24 * 60 * 60 * 1000;
159→
160→export const createInviteAction = adminAction(
161→  z.object({ email: z.string().email() }),
162→  async (ctx, { email }) => {
163→    const existingUser = await db.query.user.findFirst({
164→      where: eq(user.email, email),
165→      columns: { id: true },
166→    });
167→    if (existingUser) throw new Error("User already has an account");
168→
169→    const existingInvite = await platformInvitationRepo.findValidByEmail(email);
170→    if (existingInvite) {
171→      const inviteLink = `${clientEnv.NEXT_PUBLIC_SERVER_URL}/invite/${existingInvite.id}`;
172→      const result = await sendEmail({
173→        to: email,
174→        subject: "You're invited to RunAgents",
175→        react: PlatformInvitationEmail({ inviteLink }),
176→      });
177→      if (!result.success) {
178→        throw new Error(result.error ?? "Failed to resend email");
179→      }
180→      return { id: existingInvite.id, inviteLink };
181→    }
182→
183→    const expiresAt = new Date(Date.now() + INVITE_EXPIRATION_MS);
184→    const row = await platformInvitationRepo.create({
185→      email,
186→      invitedById: ctx.session.user.id,
187→      expiresAt,
188→    });
189→    if (!row) throw new Error("Failed to create invitation");
190→
191→    const inviteLink = `${clientEnv.NEXT_PUBLIC_SERVER_URL}/invite/${row.id}`;
192→    const result = await sendEmail({
193→      to: email,
194→      subject: "You're invited to RunAgents",
195→      react: PlatformInvitationEmail({ inviteLink }),
196→    });
197→    if (!result.success) {
198→      await platformInvitationRepo.deleteById(row.id);
199→      throw new Error(result.error ?? "Failed to send email");
200→    }
201→
202→    return { id: row.id, inviteLink };
203→  },
204→);
