"use server";

import { esc, getSandboxRuntime, runOrThrow } from "@/lib/e2b";
import { orgAction } from "@/server/action-utils";
import { z } from "zod";

export const getSessionsList = orgAction(
  z.object({ sandboxId: z.string().min(1) }),
  async ({ organizationId }, input) => {
    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
    const result = await runOrThrow(
      runtime,
      `openclaw sessions  --json`,
      "Sessions list",
    );
    const raw = result.stdout?.trim() ?? "{}";
    try {
      return JSON.parse(raw) as {
        ts: number;
        path: string;
        count: number;
        defaults: { model: string | null; contextTokens: number | null };
        sessions: unknown[];
      };
    } catch {
      throw new Error("Invalid sessions list JSON");
    }
  },
);

const sessionPatchSchema = z.object({
  sandboxId: z.string().min(1),
  key: z.string().min(1, "Session key is required"),
  patch: z.object({
    label: z.string().nullable().optional(),
    thinkingLevel: z.string().nullable().optional(),
    verboseLevel: z.string().nullable().optional(),
    reasoningLevel: z.string().nullable().optional(),
  }),
});

export const patchSession = orgAction(
  sessionPatchSchema,
  async ({ organizationId }, input) => {
    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
    const parts: string[] = [];
    if (input.patch.label !== undefined)
      parts.push(`--label ${esc(String(input.patch.label ?? ""))}`);
    if (input.patch.thinkingLevel !== undefined)
      parts.push(
        `--thinking-level ${esc(String(input.patch.thinkingLevel ?? ""))}`,
      );
    if (input.patch.verboseLevel !== undefined)
      parts.push(
        `--verbose-level ${esc(String(input.patch.verboseLevel ?? ""))}`,
      );
    if (input.patch.reasoningLevel !== undefined)
      parts.push(
        `--reasoning-level ${esc(String(input.patch.reasoningLevel ?? ""))}`,
      );
    if (parts.length === 0) return { ok: true as const };
    const opts = ` ${parts.join(" ")}`;
    await runOrThrow(
      runtime,
      `openclaw sessions patch ${esc(input.key)}${opts}`,
      "Session patch",
    );
    return { ok: true as const };
  },
);

export const deleteSession = orgAction(
  z.object({
    sandboxId: z.string().min(1),
    key: z.string().min(1, "Session key is required"),
  }),
  async ({ organizationId }, input) => {
    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
    await runOrThrow(
      runtime,
      `openclaw sessions delete ${esc(input.key)}`,
      "Session delete",
    );
    return { ok: true as const };
  },
);

