  1→"use server";
  2→
  3→import { z } from "zod";
  4→import { esc, getSandboxRuntime, runOrThrow } from "@/lib/e2b";
  5→import { orgAction } from "@/server/action-utils";
  6→import {
  7→  buildJobFlags,
  8→  jobInputSchema,
  9→  mapRawJob,
 10→  parseJson,
 11→} from "./utils/cron.utils";
 12→
 13→type RawJob = Record<string, unknown>;
 14→
 15→export const getCronStatus = orgAction(
 16→  z.object({ sandboxId: z.string().min(1) }),
 17→  async ({ organizationId }, input) => {
 18→    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
 19→    const cmd = `openclaw cron status --json`;
 20→    const result = await runOrThrow(runtime, cmd, "cron status");
 21→    return parseJson<{
 22→      enabled: boolean;
 23→      jobs: number;
 24→      nextWakeAtMs: number | null;
 25→    }>(result.stdout ?? "{}");
 26→  },
 27→);
 28→
 29→export const getCronJobs = orgAction(
 30→  z.object({
 31→    sandboxId: z.string().min(1),
 32→    includeDisabled: z.boolean().default(false),
 33→  }),
 34→  async ({ organizationId }, input) => {
 35→    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
 36→    let cmd = `openclaw cron list --json`;
 37→    if (input.includeDisabled) cmd += " --all";
 38→    const result = await runOrThrow(runtime, cmd, "cron list");
 39→    const parsed = parseJson<{ jobs?: RawJob[] }>(result.stdout ?? "{}");
 40→    const jobs = Array.isArray(parsed.jobs) ? parsed.jobs.map(mapRawJob) : [];
 41→    return { jobs, total: jobs.length };
 42→  },
 43→);
 44→
 45→export const getCronRuns = orgAction(
 46→  z.object({
 47→    sandboxId: z.string().min(1),
 48→    jobId: z.string().min(1),
 49→    limit: z.number().default(50),
 50→  }),
 51→  async ({ organizationId }, input) => {
 52→    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
 53→    const cmd = `openclaw cron runs --id ${esc(input.jobId)} --limit ${input.limit}`;
 54→    const result = await runOrThrow(runtime, cmd, "cron runs");
 55→    const parsed = parseJson<{ entries?: Record<string, unknown>[] }>(
 56→      result.stdout ?? "{}",
 57→    );
 58→    const entries = Array.isArray(parsed.entries) ? parsed.entries : [];
 59→    const runs = entries.map((e) => ({
 60→      id: (e.sessionId as string | undefined) ?? String(e.ts ?? Math.random()),
 61→      jobId: e.jobId as string,
 62→      status: (e.status as "ok" | "error" | "skipped") ?? "ok",
 63→      summary: (e.summary as string | undefined) ?? null,
 64→      error: (e.error as string | undefined) ?? null,
 65→      durationMs: (e.durationMs as number | undefined) ?? null,
 66→      startedAtMs: (e.runAtMs as number | undefined) ?? (e.ts as number),
 67→      deliveryStatus: null,
 68→    }));
 69→    return { runs, total: runs.length, hasMore: runs.length >= input.limit };
 70→  },
 71→);
 72→
 73→export const editCronJob = orgAction(
 74→  jobInputSchema.extend({ jobId: z.string().min(1) }),
 75→  async ({ organizationId }, input) => {
 76→    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
 77→    const flags = buildJobFlags(input);
 78→    const cmd = `openclaw cron edit ${esc(input.jobId)} ${flags}`;
 79→    const result = await runOrThrow(runtime, cmd, "cron edit");
 80→    return parseJson<unknown>(result.stdout ?? "{}");
 81→  },
 82→);
 83→
 84→export const deleteCronJob = orgAction(
 85→  z.object({ sandboxId: z.string().min(1), jobId: z.string().min(1) }),
 86→  async ({ organizationId }, input) => {
 87→    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
 88→    const cmd = `openclaw cron remove ${esc(input.jobId)}`;
 89→    await runOrThrow(runtime, cmd, "cron remove");
 90→  },
 91→);
 92→
 93→export const toggleCronJob = orgAction(
 94→  z.object({
 95→    sandboxId: z.string().min(1),
 96→    jobId: z.string().min(1),
 97→    enabled: z.boolean(),
 98→  }),
 99→  async ({ organizationId }, input) => {
100→    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
101→    const cmd = input.enabled
102→      ? `openclaw cron enable ${esc(input.jobId)}`
103→      : `openclaw cron disable ${esc(input.jobId)}`;
104→    await runOrThrow(runtime, cmd, "cron toggle");
105→  },
106→);
107→
108→export const runCronJob = orgAction(
109→  z.object({ sandboxId: z.string().min(1), jobId: z.string().min(1) }),
110→  async ({ organizationId }, input) => {
111→    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
112→    const cmd = `openclaw cron run ${esc(input.jobId)}`;
113→    await runOrThrow(runtime, cmd, "cron run");
114→  },
115→);
