"use server";

import { z } from "zod";
import { esc, getSandboxRuntime, runOrThrow } from "@/lib/e2b";
import { orgAction } from "@/server/action-utils";
import {
  buildJobFlags,
  jobInputSchema,
  mapRawJob,
  parseJson,
} from "./utils/cron.utils";

type RawJob = Record<string, unknown>;

export const getCronStatus = orgAction(
  z.object({ sandboxId: z.string().min(1) }),
  async ({ organizationId }, input) => {
    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
    const cmd = `openclaw cron status --json`;
    const result = await runOrThrow(runtime, cmd, "cron status");
    return parseJson<{
      enabled: boolean;
      jobs: number;
      nextWakeAtMs: number | null;
    }>(result.stdout ?? "{}");
  },
);

export const getCronJobs = orgAction(
  z.object({
    sandboxId: z.string().min(1),
    includeDisabled: z.boolean().default(false),
  }),
  async ({ organizationId }, input) => {
    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
    let cmd = `openclaw cron list --json`;
    if (input.includeDisabled) cmd += " --all";
    const result = await runOrThrow(runtime, cmd, "cron list");
    const parsed = parseJson<{ jobs?: RawJob[] }>(result.stdout ?? "{}");
    const jobs = Array.isArray(parsed.jobs) ? parsed.jobs.map(mapRawJob) : [];
    return { jobs, total: jobs.length };
  },
);

export const getCronRuns = orgAction(
  z.object({
    sandboxId: z.string().min(1),
    jobId: z.string().min(1),
    limit: z.number().default(50),
  }),
  async ({ organizationId }, input) => {
    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
    const cmd = `openclaw cron runs --id ${esc(input.jobId)} --limit ${input.limit}`;
    const result = await runOrThrow(runtime, cmd, "cron runs");
    const parsed = parseJson<{ entries?: Record<string, unknown>[] }>(
      result.stdout ?? "{}",
    );
    const entries = Array.isArray(parsed.entries) ? parsed.entries : [];
    const runs = entries.map((e) => ({
      id: (e.sessionId as string | undefined) ?? String(e.ts ?? Math.random()),
      jobId: e.jobId as string,
      status: (e.status as "ok" | "error" | "skipped") ?? "ok",
      summary: (e.summary as string | undefined) ?? null,
      error: (e.error as string | undefined) ?? null,
      durationMs: (e.durationMs as number | undefined) ?? null,
      startedAtMs: (e.runAtMs as number | undefined) ?? (e.ts as number),
      deliveryStatus: null,
    }));
    return { runs, total: runs.length, hasMore: runs.length >= input.limit };
  },
);

export const editCronJob = orgAction(
  jobInputSchema.extend({ jobId: z.string().min(1) }),
  async ({ organizationId }, input) => {
    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
    const flags = buildJobFlags(input);
    const cmd = `openclaw cron edit ${esc(input.jobId)} ${flags}`;
    const result = await runOrThrow(runtime, cmd, "cron edit");
    return parseJson<unknown>(result.stdout ?? "{}");
  },
);

export const deleteCronJob = orgAction(
  z.object({ sandboxId: z.string().min(1), jobId: z.string().min(1) }),
  async ({ organizationId }, input) => {
    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
    const cmd = `openclaw cron remove ${esc(input.jobId)}`;
    await runOrThrow(runtime, cmd, "cron remove");
  },
);

export const toggleCronJob = orgAction(
  z.object({
    sandboxId: z.string().min(1),
    jobId: z.string().min(1),
    enabled: z.boolean(),
  }),
  async ({ organizationId }, input) => {
    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
    const cmd = input.enabled
      ? `openclaw cron enable ${esc(input.jobId)}`
      : `openclaw cron disable ${esc(input.jobId)}`;
    await runOrThrow(runtime, cmd, "cron toggle");
  },
);

export const runCronJob = orgAction(
  z.object({ sandboxId: z.string().min(1), jobId: z.string().min(1) }),
  async ({ organizationId }, input) => {
    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
    const cmd = `openclaw cron run ${esc(input.jobId)}`;
    await runOrThrow(runtime, cmd, "cron run");
  },
);

