import { z } from "zod";
import { esc } from "@/lib/e2b";

type RawJob = Record<string, unknown>;

function msToEvery(ms: number): { amount: number; unit: "minutes" | "hours" | "days" } {
  const totalMinutes = ms / 60000;
  if (totalMinutes % (24 * 60) === 0) return { amount: totalMinutes / (24 * 60), unit: "days" };
  if (totalMinutes % 60 === 0) return { amount: totalMinutes / 60, unit: "hours" };
  return { amount: Math.round(totalMinutes), unit: "minutes" };
}

export function mapRawJob(raw: RawJob) {
  if (process.env.NODE_ENV === "development") {
    console.log("[cron] raw job:", JSON.stringify(raw, null, 2));
  }

  const schedule = (raw.schedule ?? {}) as Record<string, unknown>;
  const payload = (raw.payload ?? {}) as Record<string, unknown>;
  const state = (raw.state ?? {}) as Record<string, unknown>;
  const delivery = (raw.delivery ?? {}) as Record<string, unknown>;

  // Schedule kind
  const kind = (schedule.kind ?? schedule.type ?? raw.scheduleKind) as string | undefined;
  const scheduleKind: "every" | "at" | "cron" =
    kind === "every" || kind === "interval" ? "every"
      : kind === "at" || kind === "once" ? "at"
        : kind === "cron" ? "cron" : "every";

  // Payload kind — check multiple naming conventions
  const payloadKindRaw = (payload.kind ?? payload.type ?? raw.payloadKind) as string | undefined;
  const payloadKind: "systemEvent" | "agentTurn" =
    payloadKindRaw === "agent-turn" || payloadKindRaw === "agentTurn" ? "agentTurn" : "systemEvent";

  // Payload text — CLI uses --message and --system-event
  const payloadText =
    (payload.text ?? payload.message ?? payload.systemEvent ?? raw.message ?? raw.systemEvent) as string | undefined;

  // Delivery mode
  const deliveryModeRaw = (delivery.mode ?? raw.deliveryMode ?? raw.announce) as string | boolean | undefined;
  const deliveryMode: "announce" | "none" =
    deliveryModeRaw === "announce" || deliveryModeRaw === true ? "announce" : "none";

  // Every schedule — parse duration string like "30m" or everyMs
  const everyDuration = (schedule.every ?? schedule.duration) as string | undefined;
  let everyAmount: number | null = null;
  let everyUnit: "minutes" | "hours" | "days" | null = null;
  if (everyDuration && typeof everyDuration === "string") {
    const match = everyDuration.match(/^(\d+)\s*(m|h|d|min|minutes?|hours?|days?)$/i);
    if (match) {
      everyAmount = Number(match[1]);
      const u = match[2].toLowerCase();
      everyUnit = u.startsWith("d") ? "days" : u.startsWith("h") ? "hours" : "minutes";
    }
  }
  if (everyAmount == null) {
    const everyMs = schedule.everyMs as number | undefined;
    if (everyMs) {
      const parsed = msToEvery(everyMs);
      everyAmount = parsed.amount;
      everyUnit = parsed.unit;
    } else {
      everyAmount = ((schedule.everyAmount ?? schedule.amount) as number | undefined) ?? null;
      everyUnit = ((schedule.everyUnit ?? schedule.unit) as "minutes" | "hours" | "days" | undefined) ?? null;
    }
  }

  return {
    id: raw.id as string,
    name: (raw.name as string | undefined) ?? "",
    description: (raw.description as string | undefined) ?? null,
    agentId: (raw.agentId ?? raw.agent) as string | null ?? null,
    enabled: (raw.enabled as boolean | undefined) ?? true,
    sessionTarget: ((raw.sessionTarget ?? raw.session) as "main" | "isolated" | undefined) ?? "main",
    payloadKind,
    payloadText: payloadText ?? "",
    payloadModel: ((payload.model ?? raw.model) as string | undefined) ?? null,
    payloadThinking: ((payload.thinking ?? raw.thinking) as string | undefined) ?? null,
    timeoutSeconds: ((payload.timeoutSeconds ?? raw.timeoutSeconds) as number | undefined) ?? null,
    expectFinal: ((raw.expectFinal ?? payload.expectFinal) as boolean | undefined) ?? null,
    scheduleKind,
    scheduleAt: ((schedule.at ?? schedule.when) as string | undefined) ?? null,
    everyAmount,
    everyUnit,
    cronExpr: ((schedule.cron ?? schedule.expr ?? schedule.cronExpr) as string | undefined) ?? null,
    cronTz: ((schedule.cronTz ?? schedule.tz ?? raw.tz) as string | undefined) ?? null,
    stagger: ((schedule.stagger as string | undefined) ?? null),
    scheduleExact: ((schedule.exact ?? schedule.scheduleExact) as boolean | undefined) ?? null,
    deliveryMode,
    deliveryChannel: ((delivery.channel ?? raw.channel) as string | undefined) ?? null,
    deliveryTo: ((delivery.to ?? raw.to) as string | undefined) ?? null,
    deliveryBestEffort: ((delivery.bestEffort ?? raw.bestEffortDeliver) as boolean | undefined) ?? null,
    deleteAfterRun: ((raw.deleteAfterRun ?? raw["delete-after-run"]) as boolean | undefined) ?? null,
    nextRunAtMs: (state.nextRunAtMs as number | undefined) ?? null,
    updatedAtMs: (raw.updatedAtMs as number | undefined) ?? null,
  };
}

export function parseJson<T>(raw: string): T {
  try {
    return JSON.parse(raw.trim() || "{}") as T;
  } catch {
    throw new Error("Invalid JSON response from CLI");
  }
}

export const jobInputSchema = z.object({
  sandboxId: z.string().min(1),
  name: z.string().min(1),
  description: z.string().optional(),
  agentId: z.string().optional(),
  clearAgent: z.boolean().optional(),
  enabled: z.boolean(),
  scheduleKind: z.enum(["every", "at", "cron"]),
  scheduleAt: z.string().optional(),
  everyAmount: z.string().optional(),
  everyUnit: z.enum(["minutes", "hours", "days"]).optional(),
  cronExpr: z.string().optional(),
  cronTz: z.string().optional(),
  scheduleExact: z.boolean().optional(),
  stagger: z.string().optional(),
  sessionTarget: z.enum(["main", "isolated"]),
  payloadKind: z.enum(["systemEvent", "agentTurn"]),
  payloadText: z.string(),
  payloadModel: z.string().optional(),
  payloadThinking: z.string().optional(),
  timeoutSeconds: z.string().optional(),
  expectFinal: z.boolean().optional(),
  deliveryMode: z.enum(["announce", "none"]),
  deliveryChannel: z.string().optional(),
  deliveryTo: z.string().optional(),
  deliveryBestEffort: z.boolean().optional(),
  deleteAfterRun: z.boolean().optional(),
  keepAfterRun: z.boolean().optional(),
});

export type JobInput = z.infer<typeof jobInputSchema>;

const UNIT_SUFFIX: Record<string, string> = { minutes: "m", hours: "h", days: "d" };

export function buildJobFlags(input: JobInput): string {
  const parts: string[] = [];

  parts.push(`--name ${esc(input.name)}`);
  if (input.description) parts.push(`--description ${esc(input.description)}`);
  if (input.clearAgent) {
    parts.push("--clear-agent");
  } else if (input.agentId) {
    parts.push(`--agent ${esc(input.agentId)}`);
  }
  parts.push(input.enabled ? "--enable" : "--disable");

  // Schedule — uses CLI duration format like "30m", "2h", "1d"
  if (input.scheduleKind === "every" && input.everyAmount && input.everyUnit) {
    const suffix = UNIT_SUFFIX[input.everyUnit] ?? "m";
    parts.push(`--every ${Number(input.everyAmount)}${suffix}`);
  } else if (input.scheduleKind === "at" && input.scheduleAt) {
    parts.push(`--at ${esc(input.scheduleAt)}`);
  } else if (input.scheduleKind === "cron" && input.cronExpr) {
    parts.push(`--cron ${esc(input.cronExpr)}`);
    if (input.cronTz) parts.push(`--tz ${esc(input.cronTz)}`);
    if (input.scheduleExact) {
      parts.push("--exact");
    } else if (input.stagger) {
      parts.push(`--stagger ${esc(input.stagger)}`);
    }
  }

  parts.push(`--session ${input.sessionTarget}`);

  // Payload — agentTurn uses --message, systemEvent uses --system-event
  if (input.payloadKind === "agentTurn") {
    parts.push(`--message ${esc(input.payloadText)}`);
    if (input.payloadModel) parts.push(`--model ${esc(input.payloadModel)}`);
    if (input.payloadThinking) parts.push(`--thinking ${esc(input.payloadThinking)}`);
    if (input.timeoutSeconds) parts.push(`--timeout-seconds ${Number(input.timeoutSeconds)}`);
    if (input.expectFinal) parts.push("--expect-final");
  } else {
    parts.push(`--system-event ${esc(input.payloadText)}`);
  }

  // Delivery — --announce or --no-deliver
  if (input.deliveryMode === "announce") {
    parts.push("--announce");
    if (input.deliveryChannel) parts.push(`--channel ${esc(input.deliveryChannel)}`);
    if (input.deliveryTo) parts.push(`--to ${esc(input.deliveryTo)}`);
    if (input.deliveryBestEffort === true) parts.push("--best-effort-deliver");
    if (input.deliveryBestEffort === false) parts.push("--no-best-effort-deliver");
  } else {
    parts.push("--no-deliver");
  }

  if (input.deleteAfterRun) parts.push("--delete-after-run");
  if (input.keepAfterRun) parts.push("--keep-after-run");

  return parts.join(" ");
}

