  1→"use client";
  2→
  3→import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
  4→import { toast } from "sonner";
  5→import {
  6→  deleteCronJob,
  7→  editCronJob,
  8→  getCronJobs,
  9→  getCronRuns,
 10→  getCronStatus,
 11→  runCronJob,
 12→  toggleCronJob,
 13→} from "@/server/actions/cron.actions";
 14→import type {
 15→  CronJob,
 16→  CronRunLogEntry,
 17→  CronStatus,
 18→} from "../_components/types";
 19→
 20→// ── Query keys ────────────────────────────────────────────────────────────────
 21→
 22→function statusKey(sandboxId: string) {
 23→  return ["cron-status", sandboxId] as const;
 24→}
 25→
 26→function jobsKey(sandboxId: string, params: object) {
 27→  return ["cron-jobs", sandboxId, params] as const;
 28→}
 29→
 30→function runsKey(sandboxId: string, params: object) {
 31→  return ["cron-runs", sandboxId, params] as const;
 32→}
 33→
 34→// ── Status ────────────────────────────────────────────────────────────────────
 35→
 36→export function useCronStatus(sandboxId: string | null) {
 37→  return useQuery({
 38→    queryKey: statusKey(sandboxId ?? ""),
 39→    queryFn: async () => {
 40→      const result = await getCronStatus({ sandboxId: sandboxId! });
 41→      if (result && typeof result === "object" && "error" in result) {
 42→        throw Object.assign(new Error(String(result.error)), { code: result.error });
 43→      }
 44→      return result;
 45→    },
 46→    enabled: !!sandboxId,
 47→    select: (d) => d as CronStatus,
 48→  });
 49→}
 50→
 51→// ── Jobs ──────────────────────────────────────────────────────────────────────
 52→
 53→export interface CronJobsParams {
 54→  includeDisabled?: boolean;
 55→}
 56→
 57→export function useCronJobs(sandboxId: string | null, params: CronJobsParams = {}) {
 58→  return useQuery({
 59→    queryKey: jobsKey(sandboxId ?? "", params),
 60→    queryFn: async () => {
 61→      const result = await getCronJobs({
 62→        sandboxId: sandboxId!,
 63→        includeDisabled: params.includeDisabled ?? false,
 64→      });
 65→      if (result && typeof result === "object" && "error" in result) {
 66→        throw Object.assign(new Error(String(result.error)), { code: result.error });
 67→      }
 68→      return result;
 69→    },
 70→    enabled: !!sandboxId,
 71→    select: (d) => {
 72→      const raw = d as { jobs: CronJob[]; total: number };
 73→      return { jobs: raw.jobs ?? [], total: raw.total ?? 0 };
 74→    },
 75→  });
 76→}
 77→
 78→// ── Runs ──────────────────────────────────────────────────────────────────────
 79→
 80→export interface CronRunsParams {
 81→  jobId?: string | null;
 82→  limit?: number;
 83→}
 84→
 85→export function useCronRuns(sandboxId: string | null, params: CronRunsParams = {}) {
 86→  return useQuery({
 87→    queryKey: runsKey(sandboxId ?? "", params),
 88→    queryFn: async () => {
 89→      const result = await getCronRuns({
 90→        sandboxId: sandboxId!,
 91→        jobId: params.jobId!,
 92→        limit: params.limit ?? 50,
 93→      });
 94→      if (result && typeof result === "object" && "error" in result) {
 95→        throw Object.assign(new Error(String(result.error)), { code: result.error });
 96→      }
 97→      return result;
 98→    },
 99→    enabled: !!sandboxId && !!params.jobId,
100→    select: (d) => {
101→      const raw = d as { runs: CronRunLogEntry[]; total: number; hasMore: boolean };
102→      return { runs: raw.runs ?? [], total: raw.total ?? 0, hasMore: raw.hasMore ?? false };
103→    },
104→  });
105→}
106→
107→// ── Mutations ─────────────────────────────────────────────────────────────────
