"use client";

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";
import {
  deleteCronJob,
  editCronJob,
  getCronJobs,
  getCronRuns,
  getCronStatus,
  runCronJob,
  toggleCronJob,
} from "@/server/actions/cron.actions";
import type {
  CronJob,
  CronRunLogEntry,
  CronStatus,
} from "../_components/types";

// ── Query keys ────────────────────────────────────────────────────────────────

function statusKey(sandboxId: string) {
  return ["cron-status", sandboxId] as const;
}

function jobsKey(sandboxId: string, params: object) {
  return ["cron-jobs", sandboxId, params] as const;
}

function runsKey(sandboxId: string, params: object) {
  return ["cron-runs", sandboxId, params] as const;
}

// ── Status ────────────────────────────────────────────────────────────────────

export function useCronStatus(sandboxId: string | null) {
  return useQuery({
    queryKey: statusKey(sandboxId ?? ""),
    queryFn: async () => {
      const result = await getCronStatus({ sandboxId: sandboxId! });
      if (result && typeof result === "object" && "error" in result) {
        throw Object.assign(new Error(String(result.error)), { code: result.error });
      }
      return result;
    },
    enabled: !!sandboxId,
    select: (d) => d as CronStatus,
  });
}

// ── Jobs ──────────────────────────────────────────────────────────────────────

export interface CronJobsParams {
  includeDisabled?: boolean;
}

export function useCronJobs(sandboxId: string | null, params: CronJobsParams = {}) {
  return useQuery({
    queryKey: jobsKey(sandboxId ?? "", params),
    queryFn: async () => {
      const result = await getCronJobs({
        sandboxId: sandboxId!,
        includeDisabled: params.includeDisabled ?? false,
      });
      if (result && typeof result === "object" && "error" in result) {
        throw Object.assign(new Error(String(result.error)), { code: result.error });
      }
      return result;
    },
    enabled: !!sandboxId,
    select: (d) => {
      const raw = d as { jobs: CronJob[]; total: number };
      return { jobs: raw.jobs ?? [], total: raw.total ?? 0 };
    },
  });
}

// ── Runs ──────────────────────────────────────────────────────────────────────

export interface CronRunsParams {
  jobId?: string | null;
  limit?: number;
}

export function useCronRuns(sandboxId: string | null, params: CronRunsParams = {}) {
  return useQuery({
    queryKey: runsKey(sandboxId ?? "", params),
    queryFn: async () => {
      const result = await getCronRuns({
        sandboxId: sandboxId!,
        jobId: params.jobId!,
        limit: params.limit ?? 50,
      });
      if (result && typeof result === "object" && "error" in result) {
        throw Object.assign(new Error(String(result.error)), { code: result.error });
      }
      return result;
    },
    enabled: !!sandboxId && !!params.jobId,
    select: (d) => {
      const raw = d as { runs: CronRunLogEntry[]; total: number; hasMore: boolean };
      return { runs: raw.runs ?? [], total: raw.total ?? 0, hasMore: raw.hasMore ?? false };
    },
  });
}

// ── Mutations ─────────────────────────────────────────────────────────────────

export function useCronMutations(sandboxId: string | null) {
  const qc = useQueryClient();

  function invalidate() {
    if (!sandboxId) return;
    void qc.invalidateQueries({ queryKey: ["cron-status", sandboxId] });
    void qc.invalidateQueries({ queryKey: ["cron-jobs", sandboxId] });
    void qc.invalidateQueries({ queryKey: ["cron-runs", sandboxId] });
  }


  const edit = useMutation({
    mutationFn: async (data: Parameters<typeof editCronJob>[0]) => {
      const result = await editCronJob(data);
      if (result && typeof result === "object" && "error" in result) {
        throw Object.assign(new Error(String(result.error)), { code: result.error });
      }
      return result;
    },
    onSuccess: () => {
      invalidate();
      toast.success("Job updated");
    },
    onError: (e) => toast.error(e instanceof Error ? e.message : "Failed to update job"),
  });

  const remove = useMutation({
    mutationFn: async (data: Parameters<typeof deleteCronJob>[0]) => {
      const result = await deleteCronJob(data);
      if (result && typeof result === "object" && "error" in result) {
        throw Object.assign(new Error(String(result.error)), { code: result.error });
      }
      return result;
    },
    onSuccess: () => {
      invalidate();
      toast.success("Job deleted");
    },
    onError: (e) => toast.error(e instanceof Error ? e.message : "Failed to delete job"),
  });

  const toggle = useMutation({
    mutationFn: async (data: Parameters<typeof toggleCronJob>[0]) => {
      const result = await toggleCronJob(data);
      if (result && typeof result === "object" && "error" in result) {
        throw Object.assign(new Error(String(result.error)), { code: result.error });
      }
      return result;
    },
    onSuccess: () => {
      invalidate();
      toast.success("Job updated");
    },
    onError: (e) => toast.error(e instanceof Error ? e.message : "Failed to toggle job"),
  });

  const run = useMutation({
    mutationFn: async (data: Parameters<typeof runCronJob>[0]) => {
      const result = await runCronJob(data);
      if (result && typeof result === "object" && "error" in result) {
        throw Object.assign(new Error(String(result.error)), { code: result.error });
      }
      return result;
    },
    onSuccess: () => {
      invalidate();
      toast.success("Job triggered");
    },
    onError: (e) => toast.error(e instanceof Error ? e.message : "Failed to trigger job"),
  });

  const busy = edit.isPending || remove.isPending || toggle.isPending || run.isPending;

  return { edit, remove, toggle, run, busy };
}

