import { auth } from "@/lib/auth";
import { canDeploy, getOrgBillingStatus } from "@/lib/org-billing";
import { db } from "@/server/db";
import { member } from "@/server/db/models/auth.model";
import { and, eq } from "drizzle-orm";
import { headers } from "next/headers";
import { cache } from "react";
import type { z } from "zod";

/**
 * Fetches and validates the current Better Auth session from request headers.
 * Wrapped in React's cache() so multiple server actions in the same request
 * share a single session fetch — no redundant DB/cookie round-trips.
 * Throws "Unauthorized" if no valid session exists.
 */
export const getAuthedSession = cache(async () => {
  const session = await auth.api.getSession({ headers: await headers() });
  if (!session) throw new Error("Unauthorized");
  return session;
});

/** Session + admin role check. Throws if not admin. Includes headers for auth API calls. */
export const getAdminSession = cache(async () => {
  const session = await getAuthedSession();
  assertVerified(session);
  const role = (session.user as { role?: string | null }).role;
  if (role !== "admin") throw new Error("Forbidden");
  return { session, headers: await headers() };
});

/** Validate input against a Zod schema or throw */
export function parseInput<T extends z.ZodType>(
  schema: T,
  raw: unknown,
): z.infer<T> {
  const result = schema.safeParse(raw);
  if (!result.success) {
    throw new Error(result.error.issues.map((i) => i.message).join(", "));
  }
  return result.data;
}

type AuthContext = Awaited<ReturnType<typeof getAuthedSession>>;
type OrgContext = AuthContext & { organizationId: string };
export type AdminContext = Awaited<ReturnType<typeof getAdminSession>>;

/**
 * DB-level role gate: verifies the user holds an "admin" or "owner" membership
 * in the given org. Queries the DB directly (not the session) so it reflects
 * the current role even if the session is stale.
 * Throws "Forbidden: admin or owner required" if the user is a plain member,
 * or has no membership in the org at all.
 */
export async function requireAdminOrOwner(userId: string, orgId: string) {
  const membership = await db.query.member.findFirst({
    where: and(eq(member.userId, userId), eq(member.organizationId, orgId)),
  });
  if (!membership || (membership.role !== "admin" && membership.role !== "owner")) {
    throw new Error("Forbidden: admin or owner required");
  }
}

function assertVerified(session: AuthContext) {
  if (!session.user.emailVerified) throw new Error("Email not verified");
}

/** Create an authed action with optional Zod validation */
export function authedAction<TOutput>(
  handler: (ctx: AuthContext) => Promise<TOutput>,
): () => Promise<TOutput>;

export function authedAction<TInput, TOutput>(
  schema: z.ZodType<TInput>,
  handler: (ctx: AuthContext, input: TInput) => Promise<TOutput>,
): (raw: unknown) => Promise<TOutput>;

export function authedAction<TInput, TOutput>(
  schemaOrHandler: z.ZodType<TInput> | ((ctx: AuthContext) => Promise<TOutput>),
  maybeHandler?: (ctx: AuthContext, input: TInput) => Promise<TOutput>,
) {
  // No schema — just auth
  if (typeof schemaOrHandler === "function") {
    return async () => {
      const session = await getAuthedSession();
      assertVerified(session);
      return schemaOrHandler(session);
    };
  }

  // Schema + auth
  const handler = maybeHandler as (
    ctx: AuthContext,
    input: TInput,
  ) => Promise<TOutput>;
  return async (raw: unknown) => {
    const session = await getAuthedSession();
    assertVerified(session);
    const input = parseInput(schemaOrHandler, raw);
    return handler(session, input);
  };
}

/**
 * Factory for org-scoped server actions. Extends `authedAction` by also
 * requiring `session.activeOrganizationId` to be set, then injects it as
 * `ctx.organizationId` so handlers never need to null-check or re-derive it.
 * Throws "No active organization" if the session has no active org.
 *
 * Two overloads (same as authedAction):
 * - No schema: `orgAction(handler)` — auth + active org check only.
 * - With schema: `orgAction(schema, handler)` — also validates raw input.
 *
 * The handler receives `ctx: OrgContext` which extends AuthContext with
 * `organizationId: string`. Always use `ctx.organizationId` in the handler —
 * do not read from `ctx.session.activeOrganizationId` directly.
 *
 * For actions that additionally require admin/owner privileges, call
 * `requireAdminOrOwner(ctx.user.id, ctx.organizationId)` at the top of the handler.
 */
type OrgActionOptions = { skipBilling?: boolean };

/** Returned by orgAction when the billing gate blocks a request. */
export type OrgActionError = { error: string };

export function orgAction<TOutput>(
  handler: (ctx: OrgContext) => Promise<TOutput>,
  options?: OrgActionOptions,
): () => Promise<TOutput | OrgActionError>;
export function orgAction<TInput, TOutput>(
  schema: z.ZodType<TInput>,
  handler: (ctx: OrgContext, input: TInput) => Promise<TOutput>,
  options?: OrgActionOptions,
): (raw: unknown) => Promise<TOutput | OrgActionError>;
export function orgAction<TInput, TOutput>(
  schemaOrHandler: z.ZodType<TInput> | ((ctx: OrgContext) => Promise<TOutput>),
  maybeHandler?:
    | ((ctx: OrgContext, input: TInput) => Promise<TOutput>)
    | OrgActionOptions,
  maybeOptions?: OrgActionOptions,
) {
  if (typeof schemaOrHandler === "function") {
    const options = maybeHandler as OrgActionOptions | undefined;
    const skipBilling = options?.skipBilling ?? false;
    return async () => {
      try {
        const session = await getAuthedSession();
        const organizationId = session.session.activeOrganizationId;
        if (!organizationId) throw new Error("No active organization");
        if (!skipBilling) {
          const billingStatus = await getOrgBillingStatus(organizationId);
          if (!canDeploy(billingStatus))
            return { error: "SUBSCRIPTION_REQUIRED" };
        }
        return await schemaOrHandler({ ...session, organizationId });
      } catch (e) {
        return { error: e instanceof Error ? e.message : "Unknown error" };
      }
    };
  }

  const handler = maybeHandler as (
    ctx: OrgContext,
    input: TInput,
  ) => Promise<TOutput>;
  const skipBilling = maybeOptions?.skipBilling ?? false;
  return async (raw: unknown) => {
    try {
      const session = await getAuthedSession();
      const organizationId = session.session.activeOrganizationId;
      if (!organizationId) throw new Error("No active organization");
      if (!skipBilling) {
        const billingStatus = await getOrgBillingStatus(organizationId);
        if (!canDeploy(billingStatus))
          return { error: "SUBSCRIPTION_REQUIRED" };
      }
      const input = parseInput(schemaOrHandler, raw);
      return await handler({ ...session, organizationId }, input);
    } catch (e) {
      return { error: e instanceof Error ? e.message : "Unknown error" };
    }
  };
}

/** Create an admin-only action with optional Zod validation */
export function adminAction<TOutput>(
  handler: (ctx: AdminContext) => Promise<TOutput>,
): () => Promise<TOutput>;
export function adminAction<TInput, TOutput>(
  schema: z.ZodType<TInput>,
  handler: (ctx: AdminContext, input: TInput) => Promise<TOutput>,
): (raw: unknown) => Promise<TOutput>;
export function adminAction<TInput, TOutput>(
  schemaOrHandler:
    | z.ZodType<TInput>
    | ((ctx: AdminContext) => Promise<TOutput>),
  maybeHandler?: (ctx: AdminContext, input: TInput) => Promise<TOutput>,
) {
  if (typeof schemaOrHandler === "function") {
    return async () => {
      const ctx = await getAdminSession();
      return schemaOrHandler(ctx);
    };
  }

  const handler = maybeHandler as (
    ctx: AdminContext,
    input: TInput,
  ) => Promise<TOutput>;
  return async (raw: unknown) => {
    const ctx = await getAdminSession();
    const input = parseInput(schemaOrHandler, raw);
    return handler(ctx, input);
  };
}

