} from "@/app/(app)/sandboxes/[id]/channels/_components/types";
import { Button } from "@/components/ui/button";

const TELEGRAM_ICON_SRC = "/Icons/telegram.svg";
const SLACK_ICON_SRC = "/Icons/slack.svg";
const DISCORD_ICON_SRC = "/Icons/discord.svg";

import { useChannelsStatus } from "@/app/(app)/sandboxes/[id]/channels/_hooks/use-channels-status";

function isChannelConnected(options: {
  key: string;
  telegram?: TelegramStatus;
  discord?: DiscordStatus;
  slack?: SlackStatus;
}): boolean {
  const { key, telegram, discord, slack } = options;

  if (key === "telegram" && telegram) {
    return telegram.configured && telegram.running;
  }

  if (key === "discord" && discord) {
    return discord.configured && discord.running;
  }

  if (key === "slack" && slack) {
    return slack.configured && slack.running;
  }

  return false;
}

export function ChannelsView({ sandboxId }: ChannelsViewProps) {
  const {
    snapshot,
    loading,
    lastError: _lastError,
    lastSuccessAt: _lastSuccessAt,
    refetch,
  } = useChannelsStatus(sandboxId);

  const channels = snapshot?.channels as Record<string, unknown> | null;
  const telegram = (channels?.telegram ?? undefined) as
    | TelegramStatus
    | undefined;
  const discord = (channels?.discord ?? undefined) as DiscordStatus | undefined;
  const slack = (channels?.slack ?? undefined) as SlackStatus | undefined;

  const entries = [
    {
      key: "telegram",
      name: "Telegram",
      description:
        "Connect your Telegram bot to send and receive messages from your assistant.",
      isavailable: true,
    },
    {
      key: "slack",
      name: "Slack",
      description: "Bring your assistant into Slack channels and DMs.",
      isavailable: false,
    },
    {
      key: "discord",
      name: "Discord",
      description:
        "Use your assistant inside Discord servers and direct messages.",
      isavailable: false,
    },
  ] as const;

  if (loading && !snapshot) {
    return (
      <section className="flex flex-col gap-6 p-6 md:p-8">
        <div className="flex justify-start items-center">
          <div>
            <h1 className="text-xl font-semibold tracking-tight">Channels</h1>
            <p className="mt-0.5 text-sm text-muted-foreground">
              Connect your assistant to channels and receive messages from your
              users.
            </p>
          </div>
        </div>
        <section className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          <div className="col-span-full flex items-center justify-center py-16">
            <div className="flex items-center gap-3 text-muted-foreground">
              <span
                className="h-4 w-4 rounded-full border-2 border-muted-foreground border-t-transparent animate-spin"
                aria-hidden="true"
              />
              <span className="text-sm">Loading channels…</span>
            </div>
          </div>
        </section>
      </section>
    );
  }

  return (
    <section className="flex flex-col gap-6 p-6 md:p-8">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-xl font-semibold tracking-tight">Channels</h1>
          <p className="mt-0.5 text-sm text-muted-foreground">
            Connect your assistant to channels and receive messages from your
            users.
          </p>
        </div>

        <Button type="button" onClick={() => refetch()}>
          Refresh
        </Button>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 ">
        {entries.map((entry) => {
          let iconConfig = { src: DISCORD_ICON_SRC, alt: "Discord" };
          if (entry.key === "telegram") {
            iconConfig = { src: TELEGRAM_ICON_SRC, alt: "Telegram" };
          } else if (entry.key === "slack") {
            iconConfig = { src: SLACK_ICON_SRC, alt: "Slack" };
          }

          const isConnected = isChannelConnected({
            key: entry.key,
            telegram,
            discord,
            slack,
          });

          const buttonLabel = isConnected ? "Connected" : "Not Connected";

          return (
            <article
              key={entry.key}
              className="flex flex-col justify-between rounded-xl border bg-card p-5 shadow-sm"
            >
              <div className="flex items-start gap-3">
                <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-muted text-muted-foreground">
                  <Image
                    src={iconConfig.src}
                    alt={iconConfig.alt}
                    width={24}
                    height={24}
                    className="h-5 w-5"
                  />
                </div>
                <div className="space-y-1">
                  <h3 className="text-sm font-medium">{entry.name}</h3>
                  <p className="text-xs text-muted-foreground">
                    {entry.description}
                  </p>
                </div>
              </div>
              <span
                className={`mt-4 inline-flex w-fit items-center gap-1.5 rounded-full px-2.5 py-1 text-xs font-medium ${
                  isConnected
                    ? "bg-green-500/10 text-green-600"
                    : entry.isavailable
                      ? "bg-destructive/10 text-destructive"
                      : "bg-muted text-muted-foreground"
                }`}
              >
                {isConnected && (
                  <span className="h-1.5 w-1.5 rounded-full bg-green-500" />
                )}
                {!entry.isavailable
                  ? "Coming soon"
                  : isConnected
                    ? "Connected"
                    : "Not Connected"}
              </span>
            </article>
          );
        })}
      </div>
    </section>
  );
}

