"use client";

import { RefreshCw, Skull } from "lucide-react";
import { Button } from "@/components/ui/button";
import { SUBAGENT_TEMPLATES } from "../_constants/templates";
import {
  useSubAgentMutations,
  useSubAgentSessions,
} from "../_hooks/use-subagents";
import type { SubAgentSession, SubAgentTemplate } from "./types";

// ── Status badge ─────────────────────────────────────────────────────────────

const STATUS_STYLES: Record<SubAgentSession["status"], string> = {
  running: "bg-green-500/10 text-green-600",
  completed: "bg-blue-500/10 text-blue-600",
  error: "bg-destructive/10 text-destructive",
  unknown: "bg-muted text-muted-foreground",
};

function StatusBadge({ status }: { status: SubAgentSession["status"] }) {
  return (
    <span
      className={`inline-flex items-center gap-1.5 rounded-full px-2.5 py-1 text-xs font-medium ${STATUS_STYLES[status]}`}
    >
      {status === "running" && (
        <span className="h-1.5 w-1.5 rounded-full bg-green-500 animate-pulse" />
      )}
      {status.charAt(0).toUpperCase() + status.slice(1)}
    </span>
  );
}

// ── Template card ────────────────────────────────────────────────────────────

function TemplateCard({
  template,
  onSpawn,
  busy,
}: {
  template: SubAgentTemplate;
  onSpawn: () => void;
  busy: boolean;
}) {
  const Icon = template.icon;
  return (
    <article className="flex flex-col justify-between rounded-xl border bg-card p-5 shadow-sm">
      <div className="flex items-start gap-3">
        <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-muted text-muted-foreground">
          <Icon className="h-5 w-5" />
        </div>
        <div className="space-y-1">
          <h3 className="text-sm font-medium">{template.name}</h3>
          <p className="text-xs text-muted-foreground">
            {template.description}
          </p>
        </div>
      </div>
      <Button
        size="sm"
        className="mt-4 w-full"
        disabled={busy}
        onClick={onSpawn}
      >
        Spawn
      </Button>
    </article>
  );
}

// ── Session card ─────────────────────────────────────────────────────────────

function SessionCard({
  session,
  onKill,
  busy,
}: {
  session: SubAgentSession;
  onKill: () => void;
  busy: boolean;
}) {
  return (
    <div className="flex items-center justify-between rounded-lg border bg-card px-4 py-3">
      <div className="flex flex-col gap-1 min-w-0">
        <span className="text-sm font-medium truncate">
          {session.label ?? session.key}
        </span>
        <div className="flex items-center gap-2 text-xs text-muted-foreground">
          {session.model && <span>{session.model}</span>}
          {session.tokens && (
            <span>{session.tokens.total.toLocaleString()} tokens</span>
          )}
          {session.updatedAt && (
            <span>
              {new Date(session.updatedAt).toLocaleTimeString()}
            </span>
          )}
        </div>
      </div>
      <div className="flex items-center gap-2 shrink-0 ml-3">
        <StatusBadge status={session.status} />
        {session.status === "running" && (
          <Button
            variant="outline"
            size="sm"
            disabled={busy}
            onClick={onKill}
          >
            <Skull className="mr-1 h-3.5 w-3.5" />
            Kill
          </Button>
        )}
      </div>
    </div>
  );
}

// ── Main view ────────────────────────────────────────────────────────────────

export function SubAgentsView({ sandboxId }: { sandboxId: string }) {
  const {
    data: sessionsData,
    isLoading,
    refetch,
  } = useSubAgentSessions(sandboxId);
  const { spawn, kill, busy } = useSubAgentMutations(sandboxId);

  const sessions = sessionsData?.sessions ?? [];

  function handleSpawn(template: SubAgentTemplate) {
    spawn.mutate({
      sandboxId,
      agentId: template.agentId,
      message: template.defaultMessage,
    });
  }

  function handleKill(sessionKey: string) {
    kill.mutate({ sandboxId, sessionKey });
  }

  return (
    <section className="flex flex-col gap-6 p-6 md:p-8">
      {/* Header */}
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-xl font-semibold tracking-tight">Sub-Agents</h1>
          <p className="mt-0.5 text-sm text-muted-foreground">
            Spawn pre-configured sub-agents. Chat with them via Telegram.
          </p>
        </div>
        <Button
          variant="outline"
          size="sm"
          onClick={() => refetch()}
          disabled={isLoading}
        >
          <RefreshCw
            className={`mr-1.5 h-3.5 w-3.5 ${isLoading ? "animate-spin" : ""}`}
          />
          Refresh
        </Button>
      </div>

      {/* Template cards */}
      <div>
        <h2 className="mb-3 text-sm font-medium text-muted-foreground">
          Available Templates
        </h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          {SUBAGENT_TEMPLATES.map((template) => (
            <TemplateCard
              key={template.id}
              template={template}
              onSpawn={() => handleSpawn(template)}
              busy={busy}
            />
          ))}
        </div>
      </div>

      {/* Active sessions */}
      <div>
        <h2 className="mb-3 text-sm font-medium text-muted-foreground">
          Active Sessions ({sessions.length})
        </h2>
        {isLoading && sessions.length === 0 ? (
          <div className="flex items-center justify-center py-12">
            <div className="flex items-center gap-3 text-muted-foreground">
              <span
                className="h-4 w-4 rounded-full border-2 border-muted-foreground border-t-transparent animate-spin"
                aria-hidden="true"
              />
              <span className="text-sm">Loading sessions...</span>
            </div>
          </div>
        ) : sessions.length === 0 ? (
          <div className="flex items-center justify-center rounded-lg border border-dashed py-12">
            <p className="text-sm text-muted-foreground">
              No sub-agent sessions yet. Spawn one above to get started.
            </p>
          </div>
        ) : (
          <div className="flex flex-col gap-2">
            {sessions.map((session) => (
              <SessionCard
                key={session.key}
                session={session}
                onKill={() => handleKill(session.key)}
                busy={busy}
              />
            ))}
          </div>
        )}
      </div>
    </section>
  );
}

