        return key?.includes(":subagent:");
      })
      .map((s) => ({
        key: s.key as string,
        label: (s.label as string | undefined) ?? null,
        model: (s.model as string | undefined) ?? null,
        status: deriveStatus(s),
        updatedAt: (s.updatedAtMs as number | undefined) ?? null,
        tokens: parseTokens(s),
      }));

    return { sessions: subagentSessions, total: subagentSessions.length };
  },
);

// ── Kill a sub-agent session ─────────────────────────────────────────────────

export const killSubAgent = orgAction(
  z.object({
    sandboxId: z.string().min(1),
    sessionKey: z.string().min(1),
  }),
  async ({ organizationId }, input) => {
    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
    await runOrThrow(
      runtime,
      `openclaw sessions delete ${esc(input.sessionKey)}`,
      "kill subagent",
    );
    return { ok: true as const };
  },
);

// ── Helpers ──────────────────────────────────────────────────────────────────

async function agentExists(
  runtime: Sandbox,
  agentId: string,
): Promise<boolean> {
  try {
    const result = await runtime.commands.run(`openclaw agents list --json`);
    if (result.exitCode !== 0) return false;
    const parsed = JSON.parse(result.stdout?.trim() ?? "{}") as {
      agents?: { id: string }[];
    };
    const agents = Array.isArray(parsed.agents) ? parsed.agents : [];
    return agents.some((a) => a.id === agentId);
  } catch {
    return false;
  }
}

function deriveStatus(
  s: Record<string, unknown>,
): "running" | "completed" | "error" | "unknown" {
  const status = s.status as string | undefined;
  if (status === "running" || status === "active") return "running";
  if (status === "completed" || status === "done" || status === "success")
    return "completed";
  if (status === "error" || status === "failed") return "error";

  const endedAt = s.endedAtMs as number | undefined;
  const error = s.error as string | undefined;
  if (error) return "error";
  if (endedAt) return "completed";
  return "unknown";
}

function parseTokens(
  s: Record<string, unknown>,
): { input: number; output: number; total: number } | null {
  const tokens = s.tokens as Record<string, unknown> | undefined;
  if (!tokens) return null;
  const input = (tokens.input as number | undefined) ?? 0;
  const output = (tokens.output as number | undefined) ?? 0;
  return { input, output, total: input + output };
}

