interface AgentInfo {
  id: string;
  name: string;
  emoji: string | null;
  workspace: string | null;
}

async function agentExists(
  runtime: Sandbox,
  agentId: string,
): Promise<boolean> {
  try {
    const result = await runtime.commands.run(`openclaw agents list --json`);
    if (result.exitCode !== 0) return false;
    const json = extractJson(result.stdout?.trim() ?? "");
    if (!json) return false;
    const parsed = json as { agents?: { id: string }[] };
    const agents = Array.isArray(parsed.agents) ? parsed.agents : [];
    return agents.some((a) => a.id === agentId);
  } catch {
    return false;
  }
