  1→"use server";
  2→
  3→import type { Sandbox } from "e2b";
  4→import { z } from "zod";
  5→import { esc, getSandboxRuntime, runOrThrow } from "@/lib/e2b";
  6→import { orgAction } from "@/server/action-utils";
  7→
  8→// ── Create a named agent + send first message ───────────────────────────────
  9→
 10→export const createAgent = orgAction(
 11→  z.object({
 12→    sandboxId: z.string().min(1),
 13→    agentId: z.string().min(1),
 14→    name: z.string().min(1),
 15→    emoji: z.string().min(1),
 16→    systemPrompt: z.string().min(1),
 17→  }),
 18→  async ({ organizationId }, input) => {
 19→    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
 20→
 21→    const exists = await agentExists(runtime, input.agentId);
 22→
 23→    if (!exists) {
 24→      // Use $HOME so shell resolves the path (~ doesn't expand inside single quotes)
 25→      const workspace = `$HOME/.openclaw/workspace-${input.agentId}`;
 26→
 27→      // 1. Create workspace directory
 28→      await runOrThrow(
 29→        runtime,
 30→        `mkdir -p "${workspace}"`,
 31→        "create workspace",
 32→      );
 33→
 34→      // 2. Write AGENTS.md with system prompt
 35→      await runOrThrow(
 36→        runtime,
 37→        `cat > "${workspace}/AGENTS.md" << 'AGENTEOF'\n${input.systemPrompt}\nAGENTEOF`,
 38→        "write AGENTS.md",
 39→      );
 40→
 41→      // 3. Register agent via CLI (ignore "already exists" error)
 42→      const addResult = await runtime.commands.run(
 43→        `openclaw agents add ${esc(input.agentId)} --workspace "${workspace}"`,
 44→      );
 45→      const addStderr = addResult.stderr?.trim() ?? "";
 46→      if (addResult.exitCode !== 0 && !addStderr.includes("already exists")) {
 47→        throw new Error(addStderr || `agents add failed (exit ${addResult.exitCode})`);
 48→      }
 49→      console.log("[agents] register:", addResult.exitCode === 0 ? "created" : "already exists");
 50→
 51→      // 4. Set identity (name + emoji)
