    return withAgents.agents.map(agentRecordToInfo).filter((a) => a.id);
  }

  // Shape 2: top-level array
  if (Array.isArray(json)) {
    return json.map(agentRecordToInfo).filter((a) => a.id);
  }

  // Shape 3: object keyed by agent ID
  const entries = Object.entries(json as Record<string, unknown>);
  if (entries.length > 0 && typeof entries[0][1] === "object") {
    return entries.map(([key, val]) => {
      const rec = (val ?? {}) as Record<string, unknown>;
      return {
        id: (rec.id as string) ?? key,
        name: (rec.name as string | undefined) ?? key,
        emoji: (rec.emoji as string | undefined) ?? null,
        workspace: (rec.workspace as string | undefined) ?? null,
      };
    });
  }

  return [];
}

function agentRecordToInfo(raw: unknown): AgentInfo {
  const a = (raw ?? {}) as Record<string, unknown>;
  const identity = (a.identity ?? {}) as Record<string, unknown>;
  return {
    id: (a.id as string) ?? "",
    name: (identity.name as string | undefined) ?? (a.name as string | undefined) ?? (a.id as string) ?? "",
    emoji: (identity.emoji as string | undefined) ?? (a.emoji as string | undefined) ?? null,
    workspace: (a.workspace as string | undefined) ?? (a.agentDir as string | undefined) ?? null,
  };
}

interface AgentInfo {
  id: string;
  name: string;
  emoji: string | null;
  workspace: string | null;
}

async function agentExists(
  runtime: Sandbox,
  agentId: string,
): Promise<boolean> {
  try {
    // Try JSON first
    const result = await runtime.commands.run(`openclaw agents list --json`);
    if (result.exitCode === 0) {
      const json = extractJson(result.stdout?.trim() ?? "");
      if (json) {
        const parsed = json as { agents?: { id: string }[] };
        const agents = Array.isArray(parsed.agents) ? parsed.agents : [];
        if (agents.some((a) => a.id === agentId)) return true;
      }
    }

    // Fallback: plain text — check if agent ID appears in output
    const plain = await runtime.commands.run(`openclaw agents list`);
    if (plain.exitCode === 0 && plain.stdout) {
      return plain.stdout.includes(agentId);
    }

    return false;
  } catch {
    return false;
  }
}

function extractJson(raw: string): unknown | null {
  try {
    return JSON.parse(raw);
  } catch {
    // noop
  }
  const objStart = raw.indexOf("{");
  const arrStart = raw.indexOf("[");
  const start =
    objStart === -1
      ? arrStart
      : arrStart === -1
        ? objStart
        : Math.min(objStart, arrStart);
  if (start === -1) return null;
  const candidate = raw.slice(start);
  try {
    return JSON.parse(candidate);
  } catch {
    const lines = raw.split("\n");
    for (let i = lines.length - 1; i >= 0; i--) {
      const line = lines[i].trim();
      if (line.startsWith("{") || line.startsWith("[")) {
        try {
          return JSON.parse(line);
        } catch {
          continue;
        }
      }
    }
  }
  return null;
}

function deriveStatus(
  s: Record<string, unknown>,
): "running" | "completed" | "error" | "unknown" {
  const status = s.status as string | undefined;
  if (status === "running" || status === "active") return "running";
  if (status === "completed" || status === "done" || status === "success")
    return "completed";
  if (status === "error" || status === "failed") return "error";
  const endedAt = s.endedAtMs as number | undefined;
  const error = s.error as string | undefined;
  if (error) return "error";
  if (endedAt) return "completed";
  return "unknown";
}

function parseTokens(
  s: Record<string, unknown>,
): { input: number; output: number; total: number } | null {
  const tokens = s.tokens as Record<string, unknown> | undefined;
  if (!tokens) return null;
  const input = (tokens.input as number | undefined) ?? 0;
  const output = (tokens.output as number | undefined) ?? 0;
  return { input, output, total: input + output };
}

