export const createAgent = orgAction(
  z.object({
    sandboxId: z.string().min(1),
    agentId: z.string().min(1),
    name: z.string().min(1),
    emoji: z.string().min(1),
    systemPrompt: z.string().min(1),
  }),
  async ({ organizationId }, input) => {
    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);

    const exists = await agentExists(runtime, input.agentId);

    if (!exists) {
      // Use $HOME so shell resolves the path (~ doesn't expand inside single quotes)
      const workspace = `$HOME/.openclaw/workspace-${input.agentId}`;

      // 1. Create workspace directory
      await runOrThrow(
        runtime,
        `mkdir -p "${workspace}"`,
        "create workspace",
      );

      // 2. Write AGENTS.md with system prompt
      await runOrThrow(
        runtime,
        `cat > "${workspace}/AGENTS.md" << 'AGENTEOF'\n${input.systemPrompt}\nAGENTEOF`,
        "write AGENTS.md",
      );

      // 3. Register agent via CLI (ignore "already exists" error)
      const addResult = await runtime.commands.run(
        `openclaw agents add ${esc(input.agentId)} --workspace "${workspace}"`,
      );
      const addStderr = addResult.stderr?.trim() ?? "";
      if (addResult.exitCode !== 0 && !addStderr.includes("already exists")) {
        throw new Error(addStderr || `agents add failed (exit ${addResult.exitCode})`);
      }
      console.log("[agents] register:", addResult.exitCode === 0 ? "created" : "already exists");

      // 4. Set identity (name + emoji)
      await runOrThrow(
        runtime,
        `openclaw agents set-identity --agent ${esc(input.agentId)} --name ${esc(input.name)} --emoji ${esc(input.emoji)}`,
        "set identity",
      );

      // 5. Enable delegation so main agent can route tasks to named agents
      const delegationFilter = `
        .agents.defaults.subagents.maxSpawnDepth = 2 |
        .agents.defaults.subagents.allowAgents = ["*"]
      `;
      await runOrThrow(
        runtime,
        `jq '${delegationFilter}' ~/.openclaw/openclaw.json > /tmp/openclaw.json && mv /tmp/openclaw.json ~/.openclaw/openclaw.json`,
        "enable delegation",
      );

      // 6. Restart gateway to pick up new agent + delegation config
      await runOrThrow(
        runtime,
        `nohup openclaw gateway restart > /tmp/gateway-restart.log 2>&1 &`,
        "gateway restart",
      );

      await runOrThrow(runtime, "sleep 3", "wait for gateway");
    }

