130→ * - [{ id, ... }]
131→ * - { "agent-id": { ... }, ... }  (object keyed by agent ID)
132→ */
133→function parseAgentsJson(json: unknown): AgentInfo[] {
134→  if (!json || typeof json !== "object") return [];
135→
136→  // Shape 1: { agents: [...] }
137→  const withAgents = json as { agents?: unknown[] };
138→  if (Array.isArray(withAgents.agents)) {
139→    return withAgents.agents.map(agentRecordToInfo).filter((a) => a.id);
140→  }
141→
142→  // Shape 2: top-level array
143→  if (Array.isArray(json)) {
144→    return json.map(agentRecordToInfo).filter((a) => a.id);
145→  }
146→
147→  // Shape 3: object keyed by agent ID
148→  const entries = Object.entries(json as Record<string, unknown>);
149→  if (entries.length > 0 && typeof entries[0][1] === "object") {
150→    return entries.map(([key, val]) => {
151→      const rec = (val ?? {}) as Record<string, unknown>;
152→      return {
153→        id: (rec.id as string) ?? key,
154→        name: (rec.name as string | undefined) ?? key,
155→        emoji: (rec.emoji as string | undefined) ?? null,
156→        workspace: (rec.workspace as string | undefined) ?? null,
157→      };
158→    });
159→  }
160→
161→  return [];
162→}
163→
164→function agentRecordToInfo(raw: unknown): AgentInfo {
165→  const a = (raw ?? {}) as Record<string, unknown>;
166→  const identity = (a.identity ?? {}) as Record<string, unknown>;
167→  return {
168→    id: (a.id as string) ?? "",
169→    name: (identity.name as string | undefined) ?? (a.name as string | undefined) ?? (a.id as string) ?? "",
170→    emoji: (identity.emoji as string | undefined) ?? (a.emoji as string | undefined) ?? null,
171→    workspace: (a.workspace as string | undefined) ?? (a.agentDir as string | undefined) ?? null,
172→  };
173→}
174→
175→interface AgentInfo {
176→  id: string;
177→  name: string;
178→  emoji: string | null;
179→  workspace: string | null;
180→}
181→
182→async function agentExists(
183→  runtime: Sandbox,
184→  agentId: string,
185→): Promise<boolean> {
186→  try {
187→    // Try JSON first
188→    const result = await runtime.commands.run(`openclaw agents list --json`);
189→    if (result.exitCode === 0) {
190→      const json = extractJson(result.stdout?.trim() ?? "");
191→      if (json) {
192→        const parsed = json as { agents?: { id: string }[] };
193→        const agents = Array.isArray(parsed.agents) ? parsed.agents : [];
194→        if (agents.some((a) => a.id === agentId)) return true;
195→      }
196→    }
197→
198→    // Fallback: plain text — check if agent ID appears in output
199→    const plain = await runtime.commands.run(`openclaw agents list`);
200→    if (plain.exitCode === 0 && plain.stdout) {
201→      return plain.stdout.includes(agentId);
202→    }
203→
204→    return false;
205→  } catch {
206→    return false;
207→  }
208→}
209→
210→function extractJson(raw: string): unknown | null {
211→  try {
212→    return JSON.parse(raw);
213→  } catch {
214→    // noop
215→  }
216→  const objStart = raw.indexOf("{");
217→  const arrStart = raw.indexOf("[");
218→  const start =
219→    objStart === -1
220→      ? arrStart
221→      : arrStart === -1
222→        ? objStart
223→        : Math.min(objStart, arrStart);
224→  if (start === -1) return null;
225→  const candidate = raw.slice(start);
226→  try {
227→    return JSON.parse(candidate);
228→  } catch {
229→    const lines = raw.split("\n");
230→    for (let i = lines.length - 1; i >= 0; i--) {
231→      const line = lines[i].trim();
232→      if (line.startsWith("{") || line.startsWith("[")) {
233→        try {
234→          return JSON.parse(line);
235→        } catch {
236→          continue;
237→        }
238→      }
239→    }
240→  }
241→  return null;
242→}
