      content.slice(endIdx + MARKER_END.length);
  } else {
    content = content.trimEnd() + "\n\n" + specialistsBlock + "\n";
  }

  // 8. Write back
  await runtime.commands.run(`mkdir -p "${mainWorkspace}"`);
  await runOrThrow(
    runtime,
    `cat > "${mainWorkspace}/AGENTS.md" << 'MAINEOF'\n${content}\nMAINEOF`,
    "update main agent context",
  );
}

